from datetime import datetime, timedelta

def calc_incremental_count(data, apply_time_dt, short_window=7, long_window=30, distinct_field='institution_id', time_field='event_time', source='fdc_inquiry'):
    records = data.get(source, [])
    if not records:
        return 0.0

    short_start = apply_time_dt - timedelta(days=short_window)
    long_start = apply_time_dt - timedelta(days=long_window)

    short_set = set()
    long_set = set()

    for rec in records:
        t_str = rec.get(time_field)
        if not t_str:
            continue
        try:
            t = datetime.fromisoformat(t_str)
        except ValueError:
            continue

        # 防穿越逻辑：严格过滤申请时间之后的数据
        if t > apply_time_dt:
            continue

        val = rec.get(distinct_field)
        if val is None:
            continue

        if t >= short_start:
            short_set.add(val)
        if t >= long_start:
            long_set.add(val)

    return float(len(short_set - long_set))
